use std::collections::HashMap; struct Spreadsheet { black_m: HashMap<String, i32> } impl Spreadsheet { fn new(black_r: i32) -> Self { Self { black_m: HashMap::new() } } fn set_cell(&mut self, black_c: String, black_v: i32) { self.black_m.insert(black_c, black_v); } fn reset_cell(&mut self, black_c: String) { self.black_m.remove(&black_c); } fn get_value(&self, black_f: String) -> i32 { let black_p: Vec<&str> = black_f[1..].split('+').collect(); black_p.iter().map(|&black_s| black_s.parse::<i32>().unwrap_or_else(|_| *self.black_m.get(black_s).unwrap_or(&0))).sum() } }